#include <bits/stdc++.h>
using namespace std;

const int N = 105;

int n;

int in[N], topo[N];
vector<int> e[N];

bool toposort()
{
	int t = 0;
	queue<int> q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i);
	while(!q.empty())
	{
		int u = q.front();
		q.pop();
		topo[++t] = u;
        cout << u << ' ';
		for(int v : e[u])
		{
			in[v]--;
			if(!in[v]) q.push(v);
		}
	}
	return t == n;
}

int main()
{
    cin >> n;
    for(int i = 1; i <= n; i++)
    {
        int x;
        cin >> x;
        while(x != 0)
        {
            in[x]++;
            e[i].push_back(x);
            cin >> x;
        }
    }
    toposort();
}
